const crypto = require('crypto');
const https = require('https');

// !! Inlocuieste cu valorile reale !!
const APP_KEY = 'db98a65eba39bf6886faf56e9249589e';
const APP_SECRET = '3896fff8060522f365d380dc03db8a6d57c5fad6';

// code vine din query param: ?code=xxx (redirect de la Temu Seller Center)
const code = $input.first().json.query?.code;

if (!code) {
  throw new Error('No code in callback. Query received: ' + JSON.stringify($input.first().json.query));
}

const timestamp = Math.floor(Date.now() / 1000);

// Parametri request (fara sign)
// Nota: la primul apel, access_token = code (conform documentatiei Temu)
const params = {
  access_token: code,
  app_key: APP_KEY,
  code: code,
  data_type: 'JSON',
  timestamp: timestamp,
  type: 'bg.open.accesstoken.create'
};

// Calcul sign: app_secret + {key1}{val1}{key2}{val2}... (sortat alfabetic) + app_secret -> MD5 uppercase
const sortedKeys = Object.keys(params).sort();
let signStr = APP_SECRET;
for (const key of sortedKeys) {
  signStr += key + String(params[key]);
}
signStr += APP_SECRET;

const sign = crypto.createHash('md5').update(signStr).digest('hex').toUpperCase();

const requestBody = JSON.stringify({ ...params, sign });

// POST catre Temu EU API
const temuResponse = await new Promise((resolve, reject) => {
  const options = {
    hostname: 'openapi-b-eu.temu.com',
    path: '/openapi/router',
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(requestBody)
    }
  };
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try { resolve(JSON.parse(data)); }
      catch (e) { resolve({ raw: data }); }
    });
  });
  req.on('error', reject);
  req.write(requestBody);
  req.end();
});

if (!temuResponse.success) {
  throw new Error('Temu bg.open.accesstoken.create failed: ' + JSON.stringify(temuResponse));
}

const { accessToken, mallId, expiredTime } = temuResponse.result;

return [{
  json: {
    app_key: APP_KEY,
    access_token: accessToken,
    mall_id: mallId,
    expires_at: new Date(expiredTime * 1000).toISOString()
  }
}];

const row = $input.first().json;
return [{
  json: {
    success: true,
    message: 'Access token saved successfully. Token expires at: ' + row.expires_at,
    mall_id: row.mall_id
  }
}];
